}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a RULE_CONDITIONS=(
  "场地有自然灾害风险 (海岸 / 高烈度地震 / 极端温差 / 飓风) 或显著气候 stress"
  "BIM 团队 < 5 人且项目类型 < 20000 sqft / 2000 m² 且非政府强制 BIM"
  "项目要走 LEED / 绿建三星 / Passive House 认证"
  "你在中国做民营住宅项目 (2026 房地产寒冬背景)"
  "业主要求「creative freedom」但合同走 AIA B101 / 中国设计合同 standard scope"
  "做 adaptive reuse / 历史建筑改造"
)
declare -a RULE_ACTIONS=(
  "被动设计 (体形系数 / 朝向 / 遮阳 / 自然通风) + 结构系统 + 防灾策略必须在 SD 阶段共同决定, 不延后到 DD; 否则 envelope 已锁后再返工成本是设计阶段的 5-10x (业内估, 引 Architecture 2030 / AIA 2030 实际数据)"
  "用 ArchiCAD 或 Vectorworks (一人多角色 + 设计驱动 BIM) 而非 Revit + Navisworks 全栈 (后者 overhead 在小项目上吞掉时间 + 阻碍设计迭代速度)"
  "在 Programming → SD 之间锁定 envelope 性能目标 + 朝向 + 主体材料选择, 否则 DD/CD 阶段补救成本是设计阶段决策的 5-10x (业内估 AIA 2030 数据)"
  "默认走 EPC 一体化 (设计 + 施工 + 部分供材) 或先 lock 设计 + 业主预付 30% (业内估) 关键节点款 (传统纯 design fee 模式已不可持续 — 2021-2026 设计费下行 50-70% 业内估); 战略重心同步转向公共建筑 / 城市更新 / 文旅 / 乡建 / 海外项目, 不要全押民营住宅"
  "用 additional service rider 把研究 / 异常工艺 / 反复迭代写明并单独计费, 否则你免费 give away design IP (常见: 业主用前期设计去找下家便宜执行, OMA / BIG / Foster 等都被坑过 业内估)"
  "结构调研 + 危险材料 (asbestos / 铅 / 古建白蚁) + 历保 review + 旁边权益方 (邻居 / 街区 / 文物局) 先做 3-6 个月 due diligence, 设计动作 (草图 / 体块) 完全暂停"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
echo

ms_prompt "请描述当前情景 (空行结束):"
echo
SITUATION="$(ms_read_multiline)"

for i in "${!RULE_CONDITIONS[@]}"; do
  ms_section "Rule $((i+1))/${#RULE_CONDITIONS[@]}"
  echo "适用情景: ${RULE_CONDITIONS[$i]}"
  echo "推荐做法: ${RULE_ACTIONS[$i]}"
  if ms_confirm "这条规则 fit 你当前情景吗?"; then
    APPLIED_RULES+=("$((i+1))")
    ms_ok "适用 rule $((i+1))"
  fi
done

ms_buffer_append "# ${INDUSTRY} — ${TOPIC} 决策报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 情景"
ms_buffer_append ""
ms_buffer_append "$SITUATION"
ms_buffer_append ""
ms_buffer_append "## 适用规则"
ms_buffer_append ""
